import math

def solve(nums: list[int], k: int) -> int:
    n = len(nums)
    if n == 0 or k == 0:
        return 0

    pref = [0] * (n + 1)
    for i in range(n):
        pref[i + 1] = pref[i] + nums[i]

    def is_square(x: int) -> bool:
        if x < 0:
            return False
        r = int(math.isqrt(x))
        return r * r == x

    dp = [[0] * (k + 1) for _ in range(n + 1)]

    for i in range(1, n + 1):
        for j in range(k + 1):
            dp[i][j] = dp[i - 1][j]

        for m in range(i):
            s = pref[i] - pref[m]
            if is_square(s):
                length = i - m
                for j in range(1, k + 1):
                    dp[i][j] = max(dp[i][j], dp[m][j - 1] + length)

    return dp[n][k]

def solve(n: int, parents: list[int], weights: list[int], colors: list[int], k: int) -> int:
    children = [[] for _ in range(n + 1)]
    for i in range(2, n + 1):
        children[parents[i - 2]].append(i)

    order = []
    stack = [1]
    while stack:
        u = stack.pop()
        order.append(u)
        for v in children[u]:
            stack.append(v)
    order.reverse()

    dp0 = {}
    dp1 = {}

    for u in order:
        c_u = colors[u - 1]
        w_u = weights[u - 1]

        cur0 = {0: 0}
        cur1 = {c_u: w_u} if c_u <= k else {}

        for v in children[u]:
            v0 = dp0[v]
            v1 = dp1[v]

            v_max = {}
            for c_val, val in v0.items():
                v_max[c_val] = max(v_max.get(c_val, float('-inf')), val)
            for c_val, val in v1.items():
                v_max[c_val] = max(v_max.get(c_val, float('-inf')), val)

            next0 = {}
            for c1, w1 in cur0.items():
                for c2, w2 in v_max.items():
                    if c1 + c2 <= k:
                        if c1 + c2 not in next0 or w1 + w2 > next0[c1 + c2]:
                            next0[c1 + c2] = w1 + w2

            next1 = {}
            for c1, w1 in cur1.items():
                for c2, w2 in v0.items():
                    if c1 + c2 <= k:
                        if c1 + c2 not in next1 or w1 + w2 > next1[c1 + c2]:
                            next1[c1 + c2] = w1 + w2

            cur0 = next0
            cur1 = next1

        dp0[u] = cur0
        dp1[u] = cur1

    ans = 0
    for w in dp0[1].values():
        ans = max(ans, w)
    for w in dp1[1].values():
        ans = max(ans, w)

    return ans

def solve(target: list[int], m: int) -> int:
    n = len(target)
    S = set()

    for p in range(n):
        if target[p] > 0:
            k = target[p]
            if k > m:
                return -1
            l = p - k + 1
            if l < 0 or l > n - m:
                return -1
            S.add(l)

    if not S:
        if all(x == 0 for x in target):
            return 0
        return -1

    adj = {l: set() for l in S}
    in_degree = {l: 0 for l in S}

    for p in range(n):
        if target[p] == 0:
            l_min = max(0, p - m + 1)
            l_max = min(n - m, p)
            for l in range(l_min, l_max + 1):
                if l in S:
                    return -1
        else:
            k = target[p]
            l_req = p - k + 1
            l_min = max(0, p - m + 1)
            l_max = min(n - m, p)
            for l in range(l_min, l_max + 1):
                if l in S and l != l_req:
                    if l_req not in adj[l]:
                        adj[l].add(l_req)
                        in_degree[l_req] += 1

    queue = [l for l in S if in_degree[l] == 0]
    visited_count = 0

    while queue:
        u = queue.pop()
        visited_count += 1
        for v in adj[u]:
            in_degree[v] -= 1
            if in_degree[v] == 0:
                queue.append(v)

    if visited_count == len(S):
        return len(S)
    else:
        return -1

