def solve(a: list[int]) -> int:
    n = len(a)
    if n == 0:
        return 0

    # dp[i][p] represents the max relative score gain starting from cell i with power p
    dp = [[0] * (n + 2) for _ in range(n + 1)]

    for i in range(n - 1, -1, -1):
        for p in range(n - i, 0, -1):
            if i + p >= n:
                dp[i][p] = 0
            else:
                dp[i][p] = max(dp[i][p + 1], a[i + p] - dp[i + p][p])

    return a[0] + dp[0][1]

def solve(k: int, a: int, b: int, queries: list[int]) -> list[int]:
    def query_single(target: int) -> int:
        L, R = 0, 1 << k
        val_L, val_R = a, b

        while True:
            if target == L:
                return val_L
            if target == R:
                return val_R

            M = (L + R) // 2
            val_M = (val_L ^ val_R) ^ (R - L)

            if target == M:
                return val_M
            elif target < M:
                R = M
                val_R = val_M
            else:
                L = M
                val_L = val_M

    return [query_single(q) for q in queries]

