def solve(n: int, a: int, b: int) -> int:
    if a == b:
        return 0

    dist = [float('inf')] * (n + 1)
    dist[a] = 0
    pq = [(0, a)]

    while pq:
        d, u = heapq.heappop(pq)
        if d > dist[u]:
            continue
        if u == b:
            return d

        for v in range(1, n + 1):
            if u == v:
                continue
            w = max(u, v) // math.gcd(u, v)
            if d + w < dist[v]:
                dist[v] = d + w
                heapq.heappush(pq, (dist[v], v))

    return dist[b]

