def solve(n, edges):
    # Create an adjacency list representation of the tree
    tree = [[] for _ in range(n)]
    for u, v in edges:
        tree[u].append(v)
        tree[v].append(u)

    # Initialize variables to keep track of the maximum number of edges
    max_edges = 0

    # Iterate over all possible combinations of three vertices
    for a in range(n):
        for b in range(a + 1, n):
            for c in range(b + 1, n):
                # Find the paths from a to b, a to c, and b to c
                path_ab = find_path(tree, a, b)
                path_ac = find_path(tree, a, c)
                path_bc = find_path(tree, b, c)

                # Check if the subgraph induced by the vertices in the three paths is connected
                if is_connected(tree, path_ab + path_ac + path_bc):
                    # Calculate the number of edges in the subgraph
                    num_edges = calculate_edges(tree, path_ab + path_ac + path_bc)
                    # Update the maximum number of edges
                    max_edges = max(max_edges, num_edges)

    return max_edges

# Helper function to find the path between two vertices in the tree
def find_path(tree, u, v):
    # Use a queue for BFS
    queue = [(u, [u])]
    while queue:
        (node, path) = queue.pop(0)
        for neighbor in tree[node]:
            if neighbor == v:
                return path + [neighbor]
            elif neighbor not in path:
                queue.append((neighbor, path + [neighbor]))
    return None

# Helper function to check if a subgraph is connected
def is_connected(tree, vertices):
    # Use a set to keep track of visited vertices
    visited = set()
    # Start DFS from the first vertex
    stack = [vertices[0]]
    while stack:
        node = stack.pop()
        if node not in visited:
            visited.add(node)
            for neighbor in tree[node]:
                if neighbor in vertices and neighbor not in visited:
                    stack.append(neighbor)
    return len(visited) == len(vertices)

# Helper function to calculate the number of edges in a subgraph
def calculate_edges(tree, vertices):
    # Use a set to keep track of edges
    edges = set()
    # Iterate over all vertices in the subgraph
    for node in vertices:
        for neighbor in tree[node]:
            if neighbor in vertices:
                # Add the edge to the set
                edges.add(tuple(sorted((node, neighbor))))
    return len(edges)

