    directions = [(0, 1), (0, -1), (1, 0), (-1, 0)]
    def dfs(i, j):
        if i < 0 or i >= h or j < 0 or j >= w or grid[i][j] == 0:
            return 0
        grid[i][j] = 0
        return 1 + sum(dfs(i + di, j + dj) for di, dj in directions)
    return dfs(0, 0)

def solve(a):
    n = len(a)
    total_sum = sum(a)
    dp = [0] * (total_sum + 1)
    dp[0] = 1
    for num in a:
        for i in range(total_sum, num - 1, -1):
            dp[i] += dp[i - num]
    return dp[total_sum]

def solve(s1, s2):
    m, n = len(s1), len(s2)
    dp = [[float('inf')] * (n + 1) for _ in range(m + 1)]
    dp[0][0] = 0
    for i in range(m + 1):
        for j in range(n + 1):
            if i == 0 and j == 0:
                continue
            if i > 0 and s1[:i] == s2[:j]:
                dp[i][j] = 0
            if i > 0 and j > 0 and s1[i - 1] == s2[j - 1]:
                dp[i][j] = min(dp[i][j], dp[i - 1][j - 1] + 1)
            if i > 0 and j > 0 and s1[:i] == s2[n - j:]:
                dp[i][j] = min(dp[i][j], dp[i][j - 1] + 1)
    return dp[m][n]

def solve(x, operations):
    from itertools import permutations
    import math
    max_val = float('-inf')
    min_val = float('inf')
    for ops in permutations(operations):
        val = x
        for op in ops:
            if op[0] == '+':
                val += int(op[1:])
            elif op[0] == '-':
                val -= int(op[1:])
            elif op[0] == '*':
                val *= int(op[1:])
            elif op[0] == '/':
                if int(op[1:]) == 0:
                    break
                val /= int(op[1:])
        else:
            max_val = max(max_val, val)
            min_val = min(min_val, val)
    return [max_val, min_val]

def solve(n, m, edges, start, end):
    graph = [[] for _ in range(n)]
    for u, v in edges:
        graph[u].append(v)
    visited = set()
    def dfs(node):
        if node == end:
            return True
        if node in visited:
            return False
        visited.add(node)
        for neighbor in graph[node]:
            if dfs(neighbor):
                return True
        return False
    return dfs(start)

def solve(arr, target):
    left, right = 0, len(arr) - 1
    while left <= right:
        mid = (left + right) // 2
        if arr[mid] == target:
            return mid
        if arr[left] <= arr[mid]:
            if arr[left] <= target < arr[mid]:
                right = mid - 1
            else:
                left = mid + 1
        else:
            if arr[mid] < target <= arr[right]:
                left = mid + 1
            else:
                right = mid - 1
    return -1

