    for u, v in tree:
        if u not in graph:
            graph[u] = []
        if v not in graph:
            graph[v] = []
        graph[u].append(v)

    def dfs(node, parent):
        if node not in graph:
            return 0
        queries = 0
        for child in graph[node]:
            if child != parent:
                queries += 1 + dfs(child, node)
        return queries

    return dfs(0, None)

def solve(s):
    n = len(s)
    dp = [[0] * n for _ in range(n)]
    for length in range(1, n + 1):
        for i in range(n - length + 1):
            j = i + length - 1
            if length == 1:
                dp[i][j] = 0
            elif s[i] == '(' and s[j] == ')':
                dp[i][j] = dp[i + 1][j - 1] + 2
            elif s[i] == '[' and s[j] == ']':
                dp[i][j] = dp[i + 1][j - 1] + 2
            else:
                dp[i][j] = max(dp[i + 1][j], dp[i][j - 1])
    return dp[0][n - 1]

def solve(functions):
    max_independent = 0
    selected_functions = []
    for func in functions:
        is_independent = True
        for selected_func in selected_functions:
            if func[0] == selected_func[0] and func[1] == selected_func[1] and func[2] == selected_func[2]:
                is_independent = False
                break
        if is_independent:
            selected_functions.append(func)
            max_independent += 1
    return max_independent

def solve(n, tree):
    graph = [[] for _ in range(n+1)]
    for u, v in tree:
        graph[u].append(v)
        graph[v].append(u)
    labeling = ['0'] * (n+1)
    def dfs(node, parent):
        if graph[node] == [parent]:
            return
        for child in graph[node]:
            if child != parent:
                dfs(child, node)
                if labeling[child] == '0':
                    labeling[node] = '1'
    dfs(0, -1)
    return ''.join(labeling)

