def solve(edges):
    if not edges:
        return 0
    graph = {}
    for u, v in edges:
        if u not in graph:
            graph[u] = []
        if v not in graph:
            graph[v] = []
        graph[u].append(v)
        graph[v].append(u)
    visited = set()
    def dfs(node, parent):
        visited.add(node)
        children = 0
        for child in graph[node]:
            if child != parent:
                if child not in visited:
                    children += 1
                    dfs(child, node)
        if children > 1:
            return children - 1
        return 0
    return dfs(0, -1)

def solve(n, edges, k):
    # Create adjacency list representation of the tree
    tree = [[] for _ in range(n)]
    for u, v in edges:
        tree[u].append(v)
        tree[v].append(u)

    # Initialize dp table
    dp = [[0] * (k + 1) for _ in range(n)]

    # Base case: one node
    for i in range(n):
        dp[i][1] = 1

    # Fill dp table in a bottom-up manner
    for i in range(2, k + 1):
        for j in range(n):
            # For each node, consider including it or not
            include = 0
            exclude = 0
            for child in tree[j]:
                include += dp[child][i - 1]
                exclude += max(dp[child])
            dp[j][i] = max(include, exclude)

    # The answer is the maximum value in the last column of the dp table
    return max(dp[i][k] for i in range(n))
